self.addEventListener('install', e => {
  e.waitUntil((async () => {
    const core = await caches.open(CACHE);
    await core.addAll(ASSETS);
    // Tiles: best-effort individual adds — one failed tile must not block install.
    const tc = await caches.open(TILE_CACHE);
    const missing = [];
    for (const t of TILES) if (!(await tc.match(t))) missing.push(t);
    let i = 0;
    const workers = Array.from({ length: 6 }, async () => {
      while (i < missing.length) {
        const t = missing[i++];
        try { await tc.add(t); } catch {}
      }
    });
    await Promise.all(workers);
    self.skipWaiting();
  })());
});
self.addEventListener('activate', e => {
  e.waitUntil(
    caches.keys().then(keys => Promise.all(keys.filter(k => k !== CACHE && k !== TILE_CACHE).map(k => caches.delete(k))))
      .then(() => self.clients.claim())
  );
});
self.addEventListener('fetch', e => {
  e.respondWith((async () => {
    const hit = await caches.match(e.request);
    if (hit) return hit;
    const res = await fetch(e.request);
    // runtime-fill the tile cache in case install missed some
    if (res.ok && e.request.url.includes('/tiles/')) {
      const tc = await caches.open(TILE_CACHE);
      tc.put(e.request, res.clone());
    }
    return res;
  })());
});
